	}
	return user, nil
}

// GenerateUserActivityReport creates an activity report for specified users.
func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	// Build placeholders for username IN clause
	placeholders := strings.TrimRight(strings.Repeat("?,", len(usernames)), ",")

	// Base SQL query
	sql := `SELECT u.display_name, a.action_type, COUNT(*) as total_actions, SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count, AVG(a.duration_ms) as avg_duration FROM user_activity a INNER JOIN user_profile u ON a.user_id = u.id WHERE u.username IN (` + placeholders + `)`

	// Prepare arguments
	args := make([]interface{}, len(usernames))
	for i, un := range usernames {
		args[i] = un
	}

	// Add action type filter if provided
	if actionTypeFilter!= "" {
		sql += " AND a.action_type =?"
		args = append(args, actionTypeFilter)
	}

	// Add date range and group by
	sql += " AND a.created_at BETWEEN? AND? GROUP BY u.display_name, a.action_type"
	args = append(args, startDate, endDate)

	var summaries []UserActivitySummary
	_, err := o.Raw(sql, args...).QueryRows(&summaries)
	if err!= nil {
		return nil, err
	}

	return summaries, nil
}

// GenerateDepartmentReport creates a summary report grouped by a specified field.
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]DepartmentReportSummary, error) {
	// Validate groupByField
	allowedFields := map[string]bool{
		"department":   true,
		"role":         true,
		"display_name": true,
	}
	if!allowedFields[groupByField] {
		return nil, fmt.Errorf("invalid groupByField: %s, must be one of department, role, display_name", groupByField)
	}

	if len(departments) == 0 {
		return []DepartmentReportSummary{}, nil
