	sql := fmt.Sprintf(`SELECT u.%s AS group_value, COUNT(DISTINCT u.id) AS user_count, COUNT(a.id) AS total_activities FROM user_profile u LEFT JOIN user_activity a ON u.id = a.user_id WHERE u.department IN (%s) GROUP BY u.%s`, groupByField, placeholders, groupByField)

	// Prepare arguments
	args := make([]interface{}, len(departments))
	for i, d := range departments {
		args[i] = d
	}

