package main

import (
	"fmt"
	"strings"
	"time"

	"github.com/beego/beego/v2/client/orm"
)

type UserProfile struct {
	Id          int64     `orm:"column(id);pk;auto"`
	Username    string    `orm:"column(username);unique"`
	DisplayName string    `orm:"column(display_name)"`
	Email       string    `orm:"column(email)"`
	Department  string    `orm:"column(department)"`
	Role        string    `orm:"column(role)"`
	CreatedAt   time.Time `orm:"column(created_at);auto_now_add"`
}

type UserActivity struct {
	Id         int64     `orm:"column(id);pk;auto"`
	UserId     int64     `orm:"column(user_id)"`
	ActionType string    `orm:"column(action_type)"`
	Resource   string    `orm:"column(resource)"`
	IpAddress  string    `orm:"column(ip_address)"`
	Duration   int       `orm:"column(duration_ms)"`
	Success    bool      `orm:"column(success)"`
	CreatedAt  time.Time `orm:"column(created_at);auto_now_add"`
}

type UserActivitySummary struct {
	DisplayName  string
	ActionType   string
	TotalActions int
	SuccessCount int
	AvgDuration  float64
}

// RegisterUser creates a new user profile and inserts it into the database.
func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
	user := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
	}
	_, err := o.Insert(user)
	if err != nil {
		return nil, err
	}
	return user, nil
}

// GenerateUserActivityReport creates an activity report for specified users.
func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	// Build username placeholders
	placeholders := make([]string, len(usernames))
	for i := range placeholders {
		placeholders[i] = "?"
	}
	usernamePlaceholder := strings.Join(placeholders, ",")

	// Build base SQL query
	sql := `
SELECT u.display_name, a.action_type, COUNT(*) AS total_actions, SUM(CASE WHEN a.success THEN 1 ELSE 0 END) AS success_count, AVG(a.duration_ms) AS avg_duration
FROM user_activity a
INNER JOIN user_profile u ON a.user_id = u.id
WHERE u.username IN (` + usernamePlaceholder + `)
AND a.created_at BETWEEN ? AND ?`

	// Prepare parameters
	params := make([]interface{}, 0, len(usernames)+3)
	for _, u := range usernames {
		params = append(params, u)
	}
	params = append(params, startDate, endDate)

	// Add action type filter if provided
	if actionTypeFilter != "" {
		sql += " AND a.action_type = ?"
		params = append(params, actionTypeFilter)
	}

	// Add GROUP BY clause
	sql += " GROUP BY u.display_name, a.action_type"

	// Execute query and scan results
	var summaries []UserActivitySummary
	_, err := o.Raw(sql, params...).QueryRows(&summaries)
	if err != nil {
		return nil, err
	}

	return summaries, nil
}

// GenerateDepartmentReport creates a summary report grouped by a specified field.
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	// Validate groupByField
	allowedFields := map[string]bool{
		"department":   true,
		"role":         true,
		"display_name": true,
	}
	if !allowedFields[groupByField] {
		return nil, fmt.Errorf("invalid groupByField: %q, must be one of department, role, display_name", groupByField)
	}

	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	// Build department placeholders
	deptPlaceholders := strings.Repeat("?,", len(departments)-1) + "?"

	// Build SQL query with validated group field
	sql := fmt.Sprintf(`
SELECT u.%s AS group_value, COUNT(DISTINCT u.id) AS user_count, COUNT(a.id) AS total_activities
FROM user_profile u
LEFT JOIN user_activity a ON u.id = a.user_id
WHERE u.department IN (%s)
GROUP BY u.%s
`, groupByField, deptPlaceholders, groupByField)

	// Prepare parameters
	params := make([]interface{}, len(departments))
	for i, d := range departments {
		params[i] = d
	}

	// Execute query and get results as Params slice
	var results []orm.Params
	_, err := o.Raw(sql, params...).Values(&results)
	if err != nil {
		return nil, err
	}

	// Convert []orm.Params to []map[string]interface{}
	out := make([]map[string]interface{}, len(results))
	for i, p := range results {
		out[i] = map[string]interface{}(p)
	}

	return out, nil
}

