	_, err := o.Raw(sql, args...).QueryRows(&entries)
	if err!= nil {
		return nil, err
	}

	// Convert entries to map[string]interface{}
	output := make([]map[string]interface{}, len(entries))
	for i, entry := range entries {
		output[i] = map[string]interface{}{
			"group_value":       entry.GroupValue,
			"user_count":        entry.UserCount,
			"total_activities":  entry.TotalActivities,
		}
	}

	return output, nil
}

// Helper function to join strings with a separator
func joinStrings(strs []string, sep string) string {
	if len(strs) == 0 {
		return ""
	}
	result := strs[0]
	for _, s := range strs[1:] {
		result += sep + s
	}
	return result
}

