	args := make([]interface{}, 0, len(usernames)+3)

	sqlBuilder.WriteString(`SELECT u.display_name, a.action_type, COUNT(*) as total_actions, SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count, AVG(a.duration_ms) as avg_duration FROM user_activity a JOIN user_profile u ON a.user_id = u.id WHERE u.username IN (`)

	for i := range usernames {
		if i > 0 {
			sqlBuilder.WriteString(",")
		}
		sqlBuilder.WriteString("?")
		args = append(args, usernames[i])
	}

	sqlBuilder.WriteString(") AND a.created_at BETWEEN ? AND ?")
	args = append(args, startDate, endDate)

	if actionTypeFilter != "" {
		sqlBuilder.WriteString(" AND a.action_type = ?")
		args = append(args, actionTypeFilter)
	}

	sqlBuilder.WriteString(" GROUP BY u.display_name, a.action_type")

	var summaries []UserActivitySummary
	_, err := o.Raw(sqlBuilder.String(), args...).QueryRows(&summaries)
	if err != nil {
		return nil, err
	}

	return summaries, nil
}

// GenerateDepartmentReport creates a summary report grouped by a specified field.
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	allowedFields := map[string]bool{
		"department":   true,
		"role":         true,
		"display_name": true,
	}
	if !allowedFields[groupByField] {
		return nil, fmt.Errorf("invalid groupByField: %s, must be one of department, role, display_name", groupByField)
	}

	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	var sqlBuilder strings.Builder
	args := make([]interface{}, 0, len(departments))

	sqlBuilder.WriteString(fmt.Sprintf(`SELECT u.%s as group_value, COUNT(DISTINCT u.id) as user_count, COUNT(a.id) as total_activities FROM user_profile u LEFT JOIN user_activity a ON u.id = a.user_id WHERE u.department IN (`, groupByField))

	for i := range departments {
		if i > 0 {
			sqlBuilder.WriteString(",")
		}
		sqlBuilder.WriteString("?")
		args = append(args, departments[i])
	}

	sqlBuilder.WriteString(") GROUP BY u.")
	sqlBuilder.WriteString(groupByField)

	var results []orm.Params
	_, err := o.Raw(sqlBuilder.String(), args...).Values(&results)
	if err != nil {
		return nil, err
	}

